class TextEditor {
public:
    TextEditor() {
        cursor = 0;
    }

    void addText(string text) {
        textEditor.insert(cursor, text);
        cursor += text.size();
    }

    int deleteText(int k) {
        int deleted = min(k, (int)cursor);
        textEditor.erase(cursor - deleted, deleted);
        cursor -= deleted;
        return deleted;
    }

    string cursorLeft(int k) {
        cursor = max(0, (int)cursor - k);
        int len = min(10, (int)cursor);
        return textEditor.substr(cursor - len, len);
    }

    string cursorRight(int k) {
        cursor = min((int)textEditor.size(), (int)cursor + k);
        int len = min(10, (int)cursor);
        return textEditor.substr(cursor - len, len);
    }
private:
    string textEditor;
    int cursor;
};
```
efficiency: HIGH
time complexity: O(k)
